export default class WebApis extends React.Component {
  constructor(props) {
    super(props);
    // console.log("constructor");
    this.state = {
      megesena: false
    };
    // this.getJson = this.getJson.bind(this);
  }

  Chartjs = () => {
    // https://www.chartjs.org/samples/latest/utils.js

    // "use strict"; //  'use strict' is unnecessary inside of modules  strict

    window.chartColors = {
      red: "rgb(255, 99, 132)",
      orange: "rgb(255, 159, 64)",
      yellow: "rgb(255, 205, 86)",
      green: "rgb(75, 192, 192)",
      blue: "rgb(54, 162, 235)",
      purple: "rgb(153, 102, 255)",
      grey: "rgb(201, 203, 207)"
    };

    (function(global) {
      var MONTHS = [
        "January",
        "February",
        "March",
        "April",
        "May",
        "June",
        "July",
        "August",
        "September",
        "October",
        "November",
        "December"
      ];

      var COLORS = [
        "#4dc9f6",
        "#f67019",
        "#f53794",
        "#537bc4",
        "#acc236",
        "#166a8f",
        "#00a950",
        "#58595b",
        "#8549ba"
      ];

      var Samples = global.Samples || (global.Samples = {});
      var Color = global.Color;

      Samples.utils = {
        // Adapted from http://indiegamr.com/generate-repeatable-random-numbers-in-js/
        srand: function(seed) {
          this._seed = seed;
        },

        rand: function(min, max) {
          var seed = this._seed;
          min = min === undefined ? 0 : min;
          max = max === undefined ? 1 : max;
          this._seed = (seed * 9301 + 49297) % 233280;
          return min + (this._seed / 233280) * (max - min);
        },

        numbers: function(config) {
          var cfg = config || {};
          var min = cfg.min || 0;
          var max = cfg.max || 1;
          var from = cfg.from || [];
          var count = cfg.count || 8;
          var decimals = cfg.decimals || 8;
          var continuity = cfg.continuity || 1;
          var dfactor = Math.pow(10, decimals) || 0;
          var data = [];
          var i, value;

          for (i = 0; i < count; ++i) {
            value = (from[i] || 0) + this.rand(min, max);
            if (this.rand() <= continuity) {
              data.push(Math.round(dfactor * value) / dfactor);
            } else {
              data.push(null);
            }
          }

          return data;
        },

        labels: function(config) {
          var cfg = config || {};
          var min = cfg.min || 0;
          var max = cfg.max || 100;
          var count = cfg.count || 8;
          var step = (max - min) / count;
          var decimals = cfg.decimals || 8;
          var dfactor = Math.pow(10, decimals) || 0;
          var prefix = cfg.prefix || "";
          var values = [];
          var i;

          for (i = min; i < max; i += step) {
            values.push(prefix + Math.round(dfactor * i) / dfactor);
          }

          return values;
        },

        months: function(config) {
          var cfg = config || {};
          var count = cfg.count || 12;
          var section = cfg.section;
          var values = [];
          var i, value;

          for (i = 0; i < count; ++i) {
            value = MONTHS[Math.ceil(i) % 12];
            values.push(value.substring(0, section));
          }

          return values;
        },

        color: function(index) {
          return COLORS[index % COLORS.length];
        },

        transparentize: function(color, opacity) {
          var alpha = opacity === undefined ? 0.5 : 1 - opacity;
          return Color(color)
            .alpha(alpha)
            .rgbString();
        }
      };

      // DEPRECATED
      window.randomScalingFactor = function() {
        return Math.round(Samples.utils.rand(-100, 100));
      };

      // INITIALIZATION

      Samples.utils.srand(Date.now());

      // Google Analytics
      /* eslint-disable */
      if (document.location.hostname.match(/^(www\.)?chartjs\.org$/)) {
        (function(i, s, o, g, r, a, m) {
          i["GoogleAnalyticsObject"] = r;
          (i[r] =
            i[r] ||
            function() {
              (i[r].q = i[r].q || []).push(arguments);
            }),
            (i[r].l = 1 * new Date());
          (a = s.createElement(o)), (m = s.getElementsByTagName(o)[0]);
          a.async = 1;
          a.src = g;
          m.parentNode.insertBefore(a, m);
        })(
          window,
          document,
          "script",
          "//www.google-analytics.com/analytics.js",
          "ga"
        );
        ga("create", "UA-28909194-3", "auto");
        ga("send", "pageview");
      }
      /* eslint-enable */
    })(this);

    // view-source:https://www.chartjs.org/samples/latest/charts/bar/horizontal.html

    console.log("Outer Samples: ", this.Samples);

    console.log("window.randomScalingFactor: ", window.randomScalingFactor);

    // const randomScalingFactor = () => {
    //   return window.randomScalingFactor;
    // };

    var MONTHS = [
      "January",
      "February",
      "March",
      "April",
      "May",
      "June",
      "July",
      "August",
      "September",
      "October",
      "November",
      "December"
    ];
    var color = Chart.helpers.color;
    var horizontalBarChartData = {
      labels: ["January", "February", "March", "April", "May", "June", "July"],
      datasets: [
        {
          label: "Dataset 1",
          backgroundColor: color(window.chartColors.red)
            .alpha(0.5)
            .rgbString(),
          borderColor: window.chartColors.red,
          borderWidth: 1,
          data: [
            window.randomScalingFactor(),
            window.randomScalingFactor(),
            window.randomScalingFactor(),
            window.randomScalingFactor(),
            window.randomScalingFactor(),
            window.randomScalingFactor(),
            window.randomScalingFactor()
          ]
        },
        {
          label: "Dataset 2",
          backgroundColor: color(window.chartColors.blue)
            .alpha(0.5)
            .rgbString(),
          borderColor: window.chartColors.blue,
          data: [
            window.randomScalingFactor(),
            window.randomScalingFactor(),
            window.randomScalingFactor(),
            window.randomScalingFactor(),
            window.randomScalingFactor(),
            window.randomScalingFactor(),
            window.randomScalingFactor()
          ]
        }
      ]
    };

    window.onload = function() {
      var ctx = document.getElementById("chart1").getContext("2d");
      window.myHorizontalBar = new Chart(ctx, {
        type: "horizontalBar",
        data: horizontalBarChartData,
        options: {
          // Elements options apply to all of the options unless overridden in a dataset
          // In this case, we are setting the border of each horizontal bar to be 2px wide
          elements: {
            rectangle: {
              borderWidth: 2
            }
          },
          responsive: true,
          legend: {
            position: "right"
          },
          title: {
            display: true,
            text: "Chart.js Horizontal Bar Chart"
          }
        }
      });
    };

    document
      .getElementById("randomizeData")
      .addEventListener("click", function() {
        var zero = Math.random() < 0.2 ? true : false;
        horizontalBarChartData.datasets.forEach(function(dataset) {
          dataset.data = dataset.data.map(function() {
            return zero ? 0.0 : window.randomScalingFactor();
          });
        });
        window.myHorizontalBar.update();
      });

    var colorNames = Object.keys(window.chartColors);

    document.getElementById("addDataset").addEventListener("click", function() {
      var colorName =
        colorNames[horizontalBarChartData.datasets.length % colorNames.length];
      var dsColor = window.chartColors[colorName];
      var newDataset = {
        label: "Dataset " + (horizontalBarChartData.datasets.length + 1),
        backgroundColor: color(dsColor)
          .alpha(0.5)
          .rgbString(),
        borderColor: dsColor,
        data: []
      };

      for (
        var index = 0;
        index < horizontalBarChartData.labels.length;
        ++index
      ) {
        newDataset.data.push(window.randomScalingFactor());
      }

      horizontalBarChartData.datasets.push(newDataset);
      window.myHorizontalBar.update();
    });

    document.getElementById("addData").addEventListener("click", function() {
      if (horizontalBarChartData.datasets.length > 0) {
        var month =
          MONTHS[horizontalBarChartData.labels.length % MONTHS.length];
        horizontalBarChartData.labels.push(month);

        for (
          var index = 0;
          index < horizontalBarChartData.datasets.length;
          ++index
        ) {
          horizontalBarChartData.datasets[index].data.push(
            window.randomScalingFactor()
          );
        }

        window.myHorizontalBar.update();
      }
    });

    document
      .getElementById("removeDataset")
      .addEventListener("click", function() {
        horizontalBarChartData.datasets.pop();
        window.myHorizontalBar.update();
      });

    document.getElementById("removeData").addEventListener("click", function() {
      horizontalBarChartData.labels.splice(-1, 1); // remove the label first

      horizontalBarChartData.datasets.forEach(function(dataset) {
        dataset.data.pop();
      });

      window.myHorizontalBar.update();
    });

    //

    //

    // console.log("loadData: ", loadData);
    // var json = loadData;
    // json = json.slice(0, 10);

    // let dezena_1 = _.chain(json)
    //   .map(function(value, index) {
    //     console.log("value", value);
    //     // var value = _.replace(value, "/react-labs/static/media/", "");
    //     value = value["1ªdezena"];
    //     console.log("value", value);
    //     return value;
    //   })
    //   //   .first()
    //   //   .keys()
    //   .value();

    // console.log("dezena_1: ", dezena_1);

    // let dezena_2 = _.chain(json)
    //   .map(function(value, index) {
    //     console.log("value", value);
    //     // var value = _.replace(value, "/react-labs/static/media/", "");
    //     value = value["2ªdezena"];
    //     console.log("value", value);
    //     return value;
    //   })
    //   //   .first()
    //   //   .keys()
    //   .value();

    // console.log("dezena_2: ", dezena_2);

    //
  };

  componentDidMount() {
    // console.log("componentDidMount: ", this);

    this.Chartjs();
  }

  render() {
    // console.log("render: ", this);
    return (
      <>
        <Styled>
          <div className="dashboard">
            <div className="column">
              <div className="item">
                <div id="container">
                  <canvas id="chart1"></canvas>
                </div>
                <button id="randomizeData">Randomize Data</button>
                <button id="addDataset">Add Dataset</button>
                <button id="removeDataset">Remove Dataset</button>
                <button id="addData">Add Data</button>
                <button id="removeData">Remove Data</button>
              </div>
            </div>
          </div>

          <div className="dashboard">
            <div className="column">
              <div className="item">xx</div>
            </div>

            <div id="br">
              <section>
                <div className="small item">chart2</div>
                <div className="small item">chart2</div>
              </section>

              <div className="column">
                <div id="chart8" className="item">
                  chart2
                </div>
              </div>
            </div>
          </div>
        </Styled>
      </>
    );
  }
}

